svg.script:
const body = document.getElementById("breath-js");
const eyes = document.getElementById("eyes-js");
const zzz = document.getElementById("zzz-js");
const zEls = [
  document.getElementById("z1"),
  document.getElementById("z2"),
  document.getElementById("z3"),
];
const eyeL = document.getElementById("eye-l");
const eyeR = document.getElementById("eye-r");
const eyeGrad = document.getElementById("eye-grad");
const phaseReadout = document.getElementById("phase-readout");
const poseReadout = document.getElementById("pose-readout");

const EYE_BASE = {
  l: { cx: 7.75, cy: 12.02, w: 2.58, h: 1.18, tilt: -6.0 },
  r: { cx: 12.15, cy: 12.02, w: 2.58, h: 1.18, tilt: 6.0 },
};
const params = {
  period: 6.4,
  breath: 0.050,
  nodDepth: 0.40,
  nodRot: -0.55,
  eyeDrop: 0.12,
  eyeSoft: 0.10,
  flowAmp: 2.4,
  eyeStroke: 0.72,
  zInterval: 2.05,
  zLifetime: 3.15,
  zStartX: 1.40,
  zStartY: 9.25,
  zRiseDist: 5.35,
  zDriftX: -1.35,
  zMaxSize: 1.90,
  zMinSize: 1.43,
  zMaxOpacity: 0.68,
};

let startT = performance.now();
let paused = false;
let pausedAt = 0;
let pauseOffset = 0;
let lastState = null;
let glyphFlipCompensation = false;

function clamp(v, min, max) {
  return Math.max(min, Math.min(max, v));
}

function smoothstep01(x) {
  const t = clamp(x, 0, 1);
  return t * t * (3 - 2 * t);
}

function loopDistance(a, b) {
  return Math.abs(((a - b + 0.5) % 1 + 1) % 1 - 0.5);
}

function loopBump(phase, center, width) {
  const d = loopDistance(phase, center);
  if (d >= width) return 0;
  return 1 - smoothstep01(d / width);
}

function sleepyEyePath(base, drop, soft) {
  const x1 = base.cx - base.w / 2;
  const x2 = base.cx + base.w / 2;
  const cy = base.cy + drop;
  const mid = cy + base.h * 0.48 + soft;
  const c1x = base.cx - base.w * 0.17;
  const c2x = base.cx + base.w * 0.17;
  const tilt = base.tilt * 0.018;
  return `M ${x1.toFixed(2)} ${(cy - tilt).toFixed(2)} C ${c1x.toFixed(2)} ${mid.toFixed(2)} ${c2x.toFixed(2)} ${mid.toFixed(2)} ${x2.toFixed(2)} ${(cy + tilt).toFixed(2)}`;
}

function zPath(scale) {
  const w = 1.55 * scale;
  const h = 1.20 * scale;
  const x0 = glyphFlipCompensation ? w / 2 : -w / 2;
  const x1 = -x0;
  return `M ${x0.toFixed(2)} ${(-h / 2).toFixed(2)} L ${x1.toFixed(2)} ${(-h / 2).toFixed(2)} L ${x0.toFixed(2)} ${(h / 2).toFixed(2)} L ${x1.toFixed(2)} ${(h / 2).toFixed(2)}`;
}

function frameAt(seconds) {
  const phase = (seconds / params.period) % 1;
  const inhale = (1 - Math.cos(phase * Math.PI * 2)) / 2;
  const nod = loopBump(phase, 0.68, 0.15);
  const micro = Math.sin(phase * Math.PI * 2) * 0.012;
  const sx = 1 + inhale * params.breath * 0.62 + nod * 0.006;
  const sy = 1 + inhale * params.breath * 1.00 - nod * 0.008;
  const ty = -inhale * params.breath * 2.9 + nod * params.nodDepth + micro;
  const rot = nod * params.nodRot + inhale * 0.06;
  const eyeDrop = params.eyeDrop - inhale * 0.045 + nod * 0.075;
  const eyeSoft = params.eyeSoft + inhale * 0.055 + nod * 0.055;
  const eyeStroke = params.eyeStroke + inhale * 0.025 + nod * 0.02;
  const flowOffset = Math.sin(2 * Math.PI * phase) * params.flowAmp;
  return { phase, inhale, nod, sx, sy, ty, rot, eyeDrop, eyeSoft, eyeStroke, flowOffset };
}

function renderZzz(seconds) {
  params.zMinSize = params.zMaxSize * 0.75;
  const slotCount = zEls.length;
  for (let i = 0; i < slotCount; i++) {
    const bornAt = i * params.zInterval;
    const cycle = params.zInterval * slotCount;
    const age = ((seconds - bornAt) % cycle + cycle) % cycle;
    const el = zEls[i];
    if (age > params.zLifetime) {
      el.setAttribute("opacity", "0");
      continue;
    }
    const u = age / params.zLifetime;
    const x = params.zStartX + params.zDriftX * u + Math.sin(u * Math.PI * 2) * 0.16;
    const y = params.zStartY - params.zRiseDist * u;
    const size = params.zMaxSize + (params.zMinSize - params.zMaxSize) * u;
    let opacity;
    if (u < 0.18) {
      opacity = (u / 0.18) * params.zMaxOpacity;
    } else if (u < 0.68) {
      opacity = params.zMaxOpacity;
    } else {
      opacity = params.zMaxOpacity * (1 - (u - 0.68) / 0.32);
    }
    el.setAttribute("d", zPath(size));
    el.setAttribute("transform", `translate(${x.toFixed(2)} ${y.toFixed(2)}) rotate(-7)`);
    el.setAttribute("opacity", Math.max(0, opacity).toFixed(3));
  }
  zzz.setAttribute("opacity", "0.82");
}

function renderFrame(seconds) {
  const s = frameAt(seconds);
  body.setAttribute(
    "transform",
    `translate(12 12) translate(0 ${s.ty.toFixed(3)}) rotate(${s.rot.toFixed(3)}) scale(${s.sx.toFixed(4)} ${s.sy.toFixed(4)}) translate(-12 -12)`
  );
  eyeL.setAttribute("d", sleepyEyePath(EYE_BASE.l, s.eyeDrop, s.eyeSoft));
  eyeR.setAttribute("d", sleepyEyePath(EYE_BASE.r, s.eyeDrop, s.eyeSoft));
  eyeL.setAttribute("stroke-width", s.eyeStroke.toFixed(3));
  eyeR.setAttribute("stroke-width", s.eyeStroke.toFixed(3));
  eyes.setAttribute("opacity", (0.92 + s.inhale * 0.05 - s.nod * 0.03).toFixed(3));
  eyeGrad.setAttribute("y1", (3 + s.flowOffset).toFixed(2));
  eyeGrad.setAttribute("y2", (21 + s.flowOffset).toFixed(2));
  renderZzz(seconds);
  phaseReadout.textContent = `phase: ${s.phase.toFixed(2)}, inhale: ${s.inhale.toFixed(2)}, nod: ${s.nod.toFixed(2)}`;
  poseReadout.textContent = `scale: ${s.sx.toFixed(3)} ${s.sy.toFixed(3)}, ty: ${s.ty.toFixed(2)}, rot: ${s.rot.toFixed(2)}deg`;
  lastState = s;
  return s;
}

window.__clawdSetGlyphFlipCompensation = enabled => {
  const next = !!enabled;
  if (next === glyphFlipCompensation) return;
  glyphFlipCompensation = next;
  renderFrame(currentSeconds(performance.now()));
};

function currentSeconds(now) {
  if (paused) return (pausedAt - startT - pauseOffset) / 1000;
  return (now - startT - pauseOffset) / 1000;
}

function tick(now) {
  renderFrame(currentSeconds(now));
  requestAnimationFrame(tick);
}
requestAnimationFrame(tick);
